"""
MKT Context Commentary — Genesis chapters 49–50
Run: python3 scripts/zc-context-genesis-49-50.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-context/genesis.json (prior chapters; merge_comm skips already-present entries)

Key decisions in this range:
- Ch49 is the "Blessing of Jacob" / "Testament of Jacob" — one of the oldest poetic texts in the
  HB; archaic vocabulary; the commentary notes ANE deathbed-testament form and tribal-historical
  background for each oracle rather than Christological typology (that belongs to mkt-christ)
- Ch49:v10 shiloh: the most debated textual crux in Genesis; the four main interpretations are
  noted (proper noun Shiloh; construct "to whom it belongs"; verbal "tribute comes"; LXX reading)
  without deciding; Second Temple Messianic reading noted as the received tradition
- Simeon/Levi (vv.5-7): their curse is on the anger, not on the persons; historically Simeon
  was absorbed into Judah and Levi was dispersed as the priestly tribe -- both fulfillments flagged
- Zebulun (v.13): the oracle says "by the seashore" but Zebulun's actual territory was landlocked;
  the discrepancy is noted honestly
- Ch50:v2-3 embalming timeline: 40 days for natron/dehydration stage; total 70 days (the full
  Egyptian mummification period); both figures documented from Egyptian sources
- Ch50:v20 "God intended it for good": the theological climax of the Joseph narrative; the same
  verb hashav (to devise/plan) governs both the brothers' evil intent and God's good intent --
  flagged as a dual-intentionality statement, not merely post-hoc rationalization
- Ch50:v22 110 years: the Egyptian ideal lifespan in Middle Kingdom texts; Joseph dying at exactly
  110 is Egyptian-cultural expression of a divinely favored life
- Ch50:v26 aron (coffin): same word as the ark of the covenant; noted as vocabulary fact without
  imposing typological interpretation (that belongs to mkt-christ layer)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "49": {
    "1": '<p>"Gather around so I can tell you what will happen to you in days to come" — the deathbed testament is a recognized literary form in the ANE: a dying patriarch summons his sons and pronounces their tribal futures. The formula "days to come" (<em>acharit hayyamim</em>, literally "the end of the days" or "the latter days") in its OT context does not uniformly denote the eschatological end but often means "in the future" or "in the course of time" (cf. Num 24:14; Deut 31:29; Hos 3:5). The Blessing of Jacob (ch.49) is among the oldest Hebrew poetry preserved in the Bible; it uses archaic grammatical forms and vocabulary not found elsewhere, suggesting it reflects very early material.</p>',

    "2": '<p>"Assemble and listen, sons of Jacob; listen to your father Israel" — the opening call to attention follows ANE poetic parallelism: "assemble" and "listen" in the first half; "listen" again in the second half. The shift from "sons of Jacob" (tribal, genealogical identity) to "your father Israel" (covenant identity) is deliberate — the blessings are given not merely by a biological father to biological sons but by the covenant patriarch to the covenant tribes. The double naming anchors the poem between the historical and the theological.</p>',

    "3": '<p>"Reuben, you are my firstborn, my might, the first sign of my strength, excelling in honor, excelling in power" — Reuben\'s oracle opens with an accumulation of superlatives (might, first sign of strength, excelling in honor, excelling in power) that function as a foil for the deprivation that follows. The accumulation makes the reversal in v.4 more dramatic: all this prestige is forfeited. "First sign of my strength" (<em>reshit oni</em>, the beginning/firstfruit of my vigor) is the standard ANE designation of the firstborn as the father\'s initial productive power.</p>',

    "4": '<p>"Turbulent as the floods, you will no longer excel, for you went up onto your father\'s bed, onto my couch and defiled it" — the deprivation of Reuben\'s firstborn privileges is traced to the Bilhah incident of 35:22. The water metaphor — "turbulent as the floods" (<em>pachaz kamayim</em>, turbulent as water) — implies uncontrolled power that dissipates without direction. The tribal history of Reuben confirms the oracle: the tribe of Reuben occupied Transjordan east of the Dead Sea and was among the first to disappear from the historical record. The Mesha Stele (Moabite Stone, ca. 830 BCE) refers to Reuben in the past tense as a tribe that "dwelt there long ago," indicating Reuben had been absorbed or dispersed by the 9th century BCE.</p>',

    "5": '<p>"Simeon and Levi are brothers — their swords are weapons of violence" — the pairing of Simeon and Levi in the oracle reflects their joint action in the Shechem massacre (34:25-29). "Weapons of violence" (<em>kele chamas</em>) — the same phrase appears in Ps 7:16 for the wicked person\'s instruments. The oracle curses the anger rather than the persons ("cursed be their anger, so fierce" in v.7) — a distinction Jacob maintains: the sons are not cursed, but the disposition that drove their violence is.</p>',

    "6": '<p>"Let me not enter their council, let me not join their assembly, for they have killed men in their anger and hamstrung oxen as they pleased" — Jacob disassociates himself from the Shechem action with a formal distancing formula. The hamstringing of oxen may refer to cattle belonging to the Shechemites that were hamstrung during or after the massacre, making them unable to flee or work — an act of destruction beyond military necessity. The anarchy of the action (they did it "as they pleased") is what Jacob objects to.</p>',

    "7": '<p>"Cursed be their anger, so fierce, and their fury, so cruel! I will scatter them in Jacob and disperse them in Israel" — the dispersion oracle is fulfilled in two opposite ways: Simeon is absorbed into Judah (Josh 19:1-9: Simeon\'s tribal allotment is within Judah\'s territory; Simeon gradually disappears as a distinct tribe); Levi is dispersed throughout Israel as the priestly tribe with no territorial allocation (Josh 21:1-42). The Levitical dispersion, initially a punishment, becomes the mechanism for Levi\'s sacral role: scattered Levites serve as priests and teachers throughout the land.</p>',

    "8": '<p>"Judah, your brothers will praise you; your hand will be on the neck of your enemies; your father\'s sons will bow down to you" — the name Judah (<em>yehudah</em>) is connected to the root <em>yadah</em> (to praise/thank) — Leah\'s explanation at his birth was "this time I will praise the LORD" (29:35). The oracle\'s opening plays on this etymology: "your brothers will praise you" (<em>yodukha achekha</em>) — the name and the action share the same verbal root. "Your hand will be on the neck of your enemies" is the victor\'s posture in ANE iconography: the conquering king places his foot or hand on the neck of the defeated enemy (cf. Ps 110:1; Josh 10:24).</p>',

    "9": '<p>"You are a lion\'s cub, Judah; you return from the prey, my son. Like a lion he crouches and lies down, like a lioness — who dares to rouse him?" — the lion as royal symbol is deeply embedded in ANE iconography; lion imagery appears on throne decorations, royal seals, and palace gates throughout Mesopotamia and Egypt. The progression from "lion\'s cub" (<em>gur aryeh</em>) to the crouching adult lion to the unapproachable lioness represents increasing power and security. The rhetorical question "who dares to rouse him?" frames the fully established Judahite kingship as an unassailable power. The lion image is picked up in Ezek 19 (a lament for the princes of Israel as lions) and Rev 5:5.</p>',

    "10": '<p>"The scepter will not depart from Judah, nor the ruler\'s staff from between his feet, until the one to whom it belongs comes; and the obedience of the nations will be his" — the clause "until the one to whom it belongs comes" renders the most debated Hebrew crux in Genesis: <em>ad ki-yavo shiloh</em>. The main interpretations: (1) <em>shiloh</em> as the city of Shiloh, where the ark resided; (2) a construct form <em>shello</em> meaning "to whom it belongs," yielding the reading "until the one whose right it is comes" (cf. Ezek 21:27); (3) a verbal form meaning "until tribute comes to him"; (4) the Septuagint reads "until the things reserved for him arrive." By the Second Temple period, the Messianic reading was dominant in Jewish interpretation; "obedience of the nations" (<em>yiqehat ammim</em>) was read as universal homage to the coming king. For the original tribal context, the oracle asserts that royal authority belongs to and will remain with Judah\'s line.</p>',

    "11": '<p>"He will tether his donkey to a vine, his colt to the choicest branch; he will wash his garments in wine, his robes in the blood of grapes" — the imagery of extraordinary agricultural abundance: a land so rich in vineyards that tethering a donkey to a vine poses no risk to the supply — there is more than the animal could consume. Washing garments in wine (ordinarily precious) implies such surplus that wine is used for what water normally does. "Blood of grapes" (<em>dam anavim</em>) is a poetic term for wine that appears in Deut 32:14 in the same context of vineyard blessing. The Eshkol Valley, within the later territory of Judah and Benjamin, was famous in antiquity for its exceptional grapes (Num 13:23-24).</p>',

    "12": '<p>"His eyes will be darker than wine, his teeth whiter than milk" — the description applies either to the idealized ruler or to the inhabitants of the blessed land. "Darker than wine" may describe bright, sparkling eyes gleaming in contrast, or deep-colored wine-dark eyes — the Hebrew is ambiguous. "Whiter than milk" describes both prosperity (enough milk for healthy teeth) and vitality. The couplet functions as an idealization of human flourishing in the land of Judahite blessing: the people who live where the scepter rests are themselves visibly marked by abundance.</p>',

    "13": '<p>"Zebulun will live by the seashore and become a haven for ships; his border will extend toward Sidon" — the oracle is geographically puzzling: Zebulun\'s actual tribal allotment (Josh 19:10-16) was landlocked in the lower Galilee, between the Jezreel Valley and the Sea of Galilee, with no coastal boundary. However, the reference to Sidon (not Tyre, which became the dominant Phoenician city in the Iron Age) places the oracle in a pre-Israelite setting when Sidon was the preeminent Phoenician port. The oracle may project an idealized destiny, describe a period of Zebulun\'s trade-route influence toward the coast, or reflect access through Asher\'s territory. The discrepancy between oracle and historical allocation is one of the interpretive puzzles of ch.49.</p>',

    "14": '<p>"Issachar is a rawboned donkey lying down between two saddlebags" — the donkey image plays on the tribe\'s geographic position: Issachar occupied the fertile Jezreel Valley — among the most agriculturally productive land in Canaan. The donkey "lying down between two saddlebags" (<em>rovets beyn hamishpetayim</em>) evokes a beast of burden resting contentedly under its load between two packs of goods — satisfied but submissive. The "two saddlebags" may refer to the surrounding mountain ridges (Carmel to the west, the hills of Galilee to the north) between which the valley lies.</p>',

    "15": '<p>"When he sees how good is his resting place and how pleasant is his land, he will bend his shoulder to the burden and submit to forced labor" — the oracle presents a pragmatic trade: Issachar accepts political and economic subordination in exchange for access to excellent land. "Submitted to forced labor" (<em>wayhi lemas-oved</em>) — the same word (<em>mas</em>) used for the forced labor imposed on Israel in Egypt (Exod 1:11) and by Solomon (1 Kgs 5:13). Historically, the Jezreel Valley was controlled by Canaanite city-states (Megiddo, Taanach, Beth-Shan) before and during early Israelite settlement; Issachar may have operated under Canaanite labor obligations in exchange for farmland access.</p>',

    "16": '<p>"Dan will provide justice for his people as one of the tribes of Israel" — the oracle plays on Dan\'s name: <em>dan</em> means "judge" or "justice" (<em>yadin dan ammo</em>, Dan will judge his people). The added phrase "as one of the tribes of Israel" may address Dan\'s status as the son of a concubine rather than a primary wife — affirming that Dan\'s authority is fully equal to any other tribe despite the maternal hierarchy. In Judges, Dan\'s territory includes the judge Samson (Judg 13:2).</p>',

    "17": '<p>"Dan will be a serpent by the roadside, a viper along the path, that bites the horse\'s heels so that its rider tumbles backward" — the serpent image evokes guerrilla-style military tactics: not open-field battle but ambush and disruption of larger forces. The "horse\'s heel" is the point of maximum vulnerability for a mounted warrior. Historically, Dan was assigned coastal territory in the Shephelah (Josh 19:40-48) but was unable to hold it against the Philistines (Judg 1:34); the tribe migrated north and captured Laish, renaming it Dan (Judg 18), making it the northernmost boundary marker ("from Dan to Beersheba").</p>',

    "18": '<p>"I look for your deliverance, LORD" — this ejaculatory prayer interrupts the sequence of tribal oracles and is unique within the poem as a direct divine address. Several interpretations have been offered: (1) it is Jacob\'s personal prayer inserted after the Dan serpent oracle, which may have reminded him of the original serpent (Gen 3) and of death; (2) it is a liturgical refrain that interrupts the tribal series at its midpoint; (3) it reflects a moment of Jacob\'s personal awareness of mortality during the recitation. The word for "deliverance" (<em>yeshuah</em>) shares its root with the name Joshua/Jesus. The prayer is a personal note within a public document.</p>',

    "19": '<p>"Gad will be attacked by a band of raiders, but he will attack them at their heels" — wordplay on Gad\'s name: <em>gad gedud yegudennu vehu yagud aqev</em> (Gad — a troop will troop upon him, but he will troop upon their heel). The root <em>gud</em> (to raid/troop) sounds like <em>gad</em>. Gad\'s tribal territory in Gilead (Transjordan) was exposed on multiple fronts to Ammonite pressure from the east and Moabite pressure from the south; the oracle predicts a defensive resilience rather than aggressive conquest. Gad\'s warriors are praised in 1 Chr 12:8-15 for military valor.</p>',

    "20": '<p>"Asher\'s food will be rich; he will provide delicacies fit for a king" — the oracle matches Asher\'s geographic destiny: the tribe\'s territory included the fertile coastal plain north of Carmel (the Acco plain) and the western slopes of the Galilee mountains, historically renowned for olive oil production. "Delicacies fit for a king" (<em>maadanne-melek</em>) — the same word appears in Lam 4:5 for aristocratic food. In the later monarchic period, Solomon ceded twenty cities in Asher\'s territory to Hiram of Tyre in exchange for building materials (1 Kgs 9:10-13) — the rich Asherite land was used as strategic currency in international diplomacy.</p>',

    "21": '<p>"Naphtali is a doe set free that bears beautiful fawns" — the imagery of freedom and grace characterizes Naphtali; the upper Galilee territory was mountainous and well-watered. "Beautiful fawns" (<em>imre-shafer</em>) can also be rendered "beautiful words" or "eloquent speech" — if this reading is correct, the oracle praises Naphtali for eloquence. In Judg 4-5, Naphtali provides troops for Deborah and Barak\'s campaign against Sisera; in the Song of Deborah (Judg 5), Naphtali is praised alongside Zebulun for willingness to "risk their lives" — the free, swift imagery fits this profile.</p>',

    "22": '<p>"Joseph is a fruitful vine, a fruitful vine near a spring, whose branches climb over a wall" — Joseph\'s oracle is the longest after Judah\'s, reflecting his status as the most blessed of the brothers. The fruitful vine near a spring — a plant with reliable water access — produces growth that spreads beyond its original boundaries. The vine image is consistently associated with Israel\'s covenant people and their fruitfulness in the prophets (Isa 5:1-7; Ezek 17; Hos 14:7). The spreading branches also refer to the division of Joseph\'s blessing between Ephraim and Manasseh — two tribes from one patriarch — giving Joseph a double portion.</p>',

    "23": '<p>"With bitterness archers attacked him; they shot at him with hostility" — Joseph\'s historical suffering (the pit, Potiphar\'s prison, the cupbearer\'s forgetfulness) is encoded in the oracle as military attack. The archers who attacked with bitterness and hostility represent the accumulated forces of human opposition that Joseph faced — from his brothers, Potiphar\'s wife, and the prison system. The image of sustained assault without defeat prepares for v.24\'s assertion of divine sustaining.</p>',

    "24": '<p>"But his bow remained steady, his strong arms stayed limber, because of the hand of the Mighty One of Jacob, because of the Shepherd, the Rock of Israel" — the divine titles in Joseph\'s oracle are among the most significant in the patriarchal corpus: "Mighty One of Jacob" (<em>avir yaaqov</em>) is a specific epithet for Israel\'s God that appears in Isa 49:26; 60:16; Ps 132:2, 5 — an archaic title associated particularly with Jacob\'s covenant heritage. "Shepherd" (<em>roeh</em>) anticipates Ps 23 and Ezek 34\'s pastoral divine imagery. "Rock of Israel" (<em>even yisrael</em>) prefigures Isa 8:14; 28:16; Ps 118:22. The accumulation of archaic divine titles in Joseph\'s blessing signals the antiquity of the material.</p>',

    "25": '<p>"Because of your father\'s God, who helps you, because of the Almighty, who blesses you with blessings of the skies above, blessings of the deep springs below, blessings of the breast and womb" — the blessings catalog the ANE cosmic structure: sky above (rain, sun), the Tehom below (subterranean water, cf. Gen 1:2; 7:11), and biological fertility (breast and womb). The three-level cosmological blessing pattern — heavens, earth, underworld waters — reflects the ANE conception of the universe as three-tiered (cf. the Decalogue\'s "anything in heaven above or on the earth beneath or in the waters below," Exod 20:4). El-Shaddai is invoked again as in the Bethel covenant renewals (17:1; 28:3; 35:11), making Joseph\'s blessing explicitly covenantal.</p>',

    "26": '<p>"Your father\'s blessings are greater than the blessings of the ancient mountains, than the bounty of the age-old hills. Let all these rest on the head of Joseph, on the brow of the prince among his brothers" — the "ancient mountains" and "age-old hills" reference the ANE concept of mountains as primordial sacred sites, repositories of blessing and divine power. The blessings upon Joseph are presented as exceeding even these primordial sources. "Prince among his brothers" (<em>nezir echav</em>) — <em>nazir</em> here means "set apart" or "consecrated" (the same root as Nazirite vow in Num 6); Joseph is the consecrated one, set apart from his brothers by suffering and by divine destiny — a summary of the entire Joseph narrative in a single phrase.</p>',

    "27": '<p>"Benjamin is a ravenous wolf; in the morning he devours the prey, in the evening he divides the plunder" — the most warlike image in the tribal oracles; the wolf imagery stands in contrast to Joseph\'s vine and Judah\'s lion. Benjamin\'s territory (between Judah and Ephraim, astride the central highlands\' main north-south route) made it a perennial battle zone. The tribe produced notable warriors: the left-handed judge Ehud who killed Eglon of Moab (Judg 3:15-30); King Saul and his son Jonathan (1 Sam 9:1-2); the "mighty warriors" listed in 1 Chr 8. Paul the Apostle identifies as "a Hebrew of Hebrews, from the tribe of Benjamin" (Phil 3:5; Rom 11:1).</p>',

    "28": '<p>"All these are the twelve tribes of Israel, and this is what their father said to them when he blessed them, giving each the blessing appropriate to him" — the summary verse confirms that the oracles (including the curses on Reuben, Simeon, and Levi) are all categorized as "blessings." The ANE understood a deathbed patriarchal declaration — however negative its content — as an authoritative prophetic statement about future destiny. Even Reuben\'s demotion is a "blessing" in the sense of a true oracle about the tribe\'s future role. The "twelve tribes" inventory here functions as the foundation document for Israel\'s tribal system.</p>',

    "29": '<p>"I am about to be gathered to my people. Bury me with my fathers in the cave in the field of Ephron the Hittite" — Jacob\'s burial instructions specify the Machpelah cave with legal precision for the third time in Genesis (23:17-19 was the original purchase; 25:9-10 was Abraham and Sarah\'s burial record; here is the directive for Jacob\'s own burial). The formula "gathered to my people" (<em>ne-esaf el-ammi</em>) is the standard ANE euphemism for death understood as joining the ancestral community; it appears in the patriarchal death notices (25:8, 17; 35:29; 49:29, 33). The precision of the burial instruction is also a covenant-land claim: by specifying burial in Canaan\'s purchased ground, Jacob stakes an ancestral right to the land even in death.</p>',

    "30": '<p>"In the cave in the field of Machpelah, near Mamre in Canaan, which Abraham bought along with the field as a burial place from Ephron the Hittite" — the full legal description (cave, field, location, original seller) constitutes a property record that any Hittite legal convention would recognize as establishing clear title. The same formula was used in 23:17-20. The repetition of the legal description in Jacob\'s deathbed speech serves the same function as a modern title document: establishing the chain of ownership from the original commercial transaction to the current rightful occupants.</p>',

    "31": '<p>"There Abraham and his wife Sarah were buried, there Isaac and his wife Rebekah were buried, and there I buried Leah" — the burial inventory is a family registry: Abraham, Sarah, Isaac, Rebekah, Leah. The explicit naming of Leah is significant: she will be permanently interred in the patriarchal burial cave, while Rachel was buried "on the way" near Bethlehem (35:19). The listing confirms Leah\'s status as Jacob\'s covenant wife — despite being the less-loved of the two, she shares in the patriarchal burial with full honor. Rachel\'s absence from Machpelah and Leah\'s presence is the final resolution of the Rachel-Leah competition that ran through chs.29-35.</p>',

    "32": '<p>"The field and the cave in it were bought from the Hittites" — the final legal confirmation in the burial instruction. The repeated emphasis on the commercial transaction — bought, not seized, not given, not occupied illegally — is a legal and theological argument: Israel\'s first Canaanite property was acquired through legitimate market transaction, establishing covenant right through commerce before conquest.</p>',

    "33": '<p>"When Jacob had finished giving instructions to his sons, he drew his feet up into the bed, breathed his last and was gathered to his people" — the death notice for Jacob uses all the standard patriarchal formulae: the completion of the final speech, the physical act of drawing his feet onto the bed (composing himself for death — a final gesture of intentionality and dignity), the breath-departure (<em>vayigva</em>, he expired), and the "gathered to his people" formula used for Abraham (25:8), Ishmael (25:17), and Isaac (35:29). Jacob dies at 147 years (47:28), having lived the longest of the three patriarchs. The death is peaceful and deliberate — Jacob has finished what he needed to say and simply completes the dying he began in 47:29.</p>',
  },
  "50": {
    "1": '<p>"Joseph threw himself on his father and wept over him and kissed him" — the three physical responses (threw himself, wept, kissed) are the ANE mourning gestures for a beloved person\'s death. "Threw himself on his father" (<em>vayippol yosef al-pene aviv</em>, fell upon his father\'s face) is an embrace of the dead — physically covering the father\'s face with his own. The kiss of the dead is documented in ANE mourning practices and represents the final goodbye before the body is prepared. Joseph\'s grief is the most physically expressed mourning in the entire patriarchal narrative.</p>',

    "2": '<p>"Joseph directed the physicians in his service to embalm his father Israel. So the physicians embalmed him" — the physician-embalmers (<em>rofe\'im</em>, healers) performing the embalming rather than professional Egyptian undertakers reflects Joseph\'s use of his personal court staff for the family\'s care. Egyptian mummification was a complex, multi-stage process: removal of organs (excepting the heart), natron desiccation, wrapping, and anointing. That Joseph has access to court physicians capable of full mummification demonstrates his high social position. Embalming was not an Israelite practice — Jacob is the only patriarch embalmed, and Joseph himself (50:26); both die in Egypt.</p>',

    "3": '<p>"Taking a full forty days, for that was the time required for embalming. And the Egyptians mourned for him seventy days" — Egyptian textual evidence documents the full mummification process at 70 days, with 40 days specifically required for the natron-dehydration stage. The Egyptians\' 70-day mourning period for Jacob matches the total mummification timeline and also approximates the mourning period for pharaohs (72 days). That a Canaanite foreigner — even the vizier\'s father — received a 70-day Egyptian mourning period indicates extraordinary honor. Jacob\'s 70 days places him in the highest category of honored foreigners, approximately equivalent to royal mourning protocol.</p>',

    "4": '<p>"When the days of mourning had passed, Joseph said to Pharaoh\'s household, \'If I have found favor in your eyes, speak to Pharaoh for me\'" — Joseph does not approach Pharaoh directly. Two explanations are offered by ancient commentators: (1) mourning conventions required that a mourner not appear at court (disheveled, unshaved) for the mourning period; (2) a senior official approaching the king about a personal matter required an intermediary by court protocol. Joseph uses "Pharaoh\'s household" as the channel — the same household that had heard his weeping at the revelation to his brothers (45:2) and would have known the family situation.</p>',

    "5": '<p>"My father made me swear an oath and said, \'I am about to die; bury me in the tomb I dug for myself in the land of Canaan\'" — the oath is accurately reported (47:29-31); Joseph presents the burial request not as his personal desire but as a sworn obligation to a dying father — an appeal to the ANE\'s high regard for deathbed oaths, which were considered inviolable. "The tomb I dug for myself" refers to the Machpelah cave, purchased rather than literally excavated by Jacob; the formula "the tomb I dug" may be an idiom for any burial place one has arranged, or Jacob may have made additional physical preparations at Machpelah during his time in Canaan before moving to Egypt.</p>',

    "6": '<p>"Pharaoh said, \'Go up and bury your father, as he made you swear to do\'" — Pharaoh\'s response is immediate and unconditional: he appeals to the same authority Joseph invoked — the sworn oath. In the ANE, deathbed oaths were among the most sacrosanct obligations; refusing to allow their fulfillment would be a serious moral and religious failing. Pharaoh grants the request without deliberation because he understands the obligation\'s inviolable character. The permission makes Jacob\'s burial in Canaan an Egyptian state-authorized action, not a private Israelite undertaking.</p>',

    "7": '<p>"All Pharaoh\'s officials accompanied him — the dignitaries of his court and all the dignitaries of Egypt" — the funeral procession is a state event: "all Pharaoh\'s officials" (<em>kol-avde faraoh</em>) and "the dignitaries of his court and all the dignitaries of Egypt" (<em>ziknei veyto vekhol-ziknei eretz-mitzrayim</em>). The word <em>zaqen</em> (elder/dignitary) designates the senior leadership. Egypt\'s senior officials accompanying Joseph to bury his father in Canaan transforms a family burial into an international political event — an Egyptian state visit to the land that will eventually be left by Egypt\'s escaped slaves.</p>',

    "8": '<p>"Together with all the members of Joseph\'s household and his brothers and those belonging to his father\'s household. Only their children and their flocks and herds were left in Goshen" — the detail that children and livestock were left in Goshen is practical (the journey was long and difficult for young children) and legally significant: it means the family has not abandoned its Egyptian residence. The children and animals remaining in Goshen are essentially hostages for the traveling party\'s return — a common ANE security practice for allowing foreign nationals temporary travel outside the country.</p>',

    "9": '<p>"Chariots and horsemen also went up with him. It was a very large company" — the military escort (chariots and cavalry) is both protective and ceremonial; a vizier traveling outside Egypt\'s borders with a large foreign entourage would require military protection. Egyptian chariot forces were the elite military arm of the New Kingdom; their presence signals the highest level of official honor. The phrase "a very large company" (<em>machaneh kaved meod</em>) — literally "a very heavy/weighty camp" — echoes the weight/honor vocabulary; the word <em>kaved</em> (heavy/weighty) is the root of the word for "glory" (<em>kavod</em>).</p>',

    "10": '<p>"When they reached the threshing floor of Atad, near the Jordan, they lamented loudly and bitterly; and there Joseph observed a seven-day period of mourning for his father" — the threshing floor of Atad is in Transjordan (east of the Jordan), the last stopping point before crossing into Canaan. The seven-day mourning period (<em>shivat yamim</em>) is the standard ANE mourning duration (cf. Job 2:13: the friends sat with Job seven days; 1 Sam 31:13: Jabesh-Gilead mourned Saul seven days). The enormous Egyptian entourage observing mourning rites just outside Canaan is visible and memorable to the local Canaanite population.</p>',

    "11": '<p>"When the Canaanites who lived there saw the mourning at the threshing floor of Atad, they said, \'The Egyptians are holding a solemn ceremony of mourning.\' That is why that place near the Jordan is called Abel Mizraim" — <em>avel mitzrayim</em> combines two possible meanings: "meadow of Egypt" (<em>avel</em> = meadow/water-meadow) and "mourning of Egypt" (<em>aval</em> = to mourn; <em>evel</em> = mourning). The Canaanites\' identification of the mourners as Egyptians rather than Israelites reflects both the size and style of the Egyptian-format cortege: the chariots, the official dress, the formal lament. The place-name commemorates that Egypt came to Canaan to bury — a geographical paradox, since Egypt usually received things from Canaan rather than bringing them there.</p>',

    "12": '<p>"So Jacob\'s sons did as he had commanded them" — the brief confirmation of compliance emphasizes the sons\' obedience to Jacob\'s final instruction. The command was given under oath (47:31); the fulfillment honors that oath. The narrative\'s structural parallel to Abraham\'s burial (25:9: both Ishmael and Isaac buried Abraham together) is completed: both Esau and Jacob buried Isaac together (35:29); now all twelve sons bury Jacob together — the covenant family unified in the final filial act.</p>',

    "13": '<p>"They carried him to the land of Canaan and buried him in the cave in the field of Machpelah, near Mamre, which Abraham had bought along with the field as a burial place from Ephron the Hittite" — the burial formula repeats the Machpelah legal description for the fourth time in Genesis (23:17-20; 25:9-10; 49:29-32; now 50:13). The legal precision serves as a running title-deed: the reader knows exactly what property is at stake and that it was legitimately purchased. The burial of Jacob in Machpelah closes the patriarchal burial sequence: Abraham and Sarah, Isaac and Rebekah, Jacob — all in the purchased cave.</p>',

    "14": '<p>"After burying his father, Joseph returned to Egypt, together with his brothers and all the others who had gone with him to bury his father" — the return to Egypt is the fulfillment of the security arrangement implied in v.8 (children and livestock left in Goshen). The journey served its stated purpose (burying Jacob in Machpelah) and the family returns. The return marks a narrative turning point: Jacob is buried in Canaan, the connection to the patriarchal land is maintained through the tomb, but the living family is in Egypt — and there they will remain until Moses.</p>',

    "15": '<p>"When Joseph\'s brothers saw that their father was dead, they said, \'What if Joseph holds a grudge against us and pays us back for all the wrongs we did to him?\'" — the brothers\' anxiety after Jacob\'s death is psychologically realistic: Jacob\'s presence had been a social guarantor of peace — the shared loyalty to the father created an implicit truce. With Jacob gone, they fear the calculus of power reasserts itself: Joseph has the authority to revenge himself and may have maintained the reconciliation only out of filial loyalty to Jacob. The fear reveals how incompletely the ch.45 revelation resolved their guilt and anxiety; they have not fully believed that Joseph has forgiven them.</p>',

    "16": '<p>"So they sent word to Joseph, saying, \'Your father left these instructions before he died\'" — the message through intermediaries rather than direct approach mirrors Joseph\'s own diplomatic navigation in approaching Pharaoh through intermediaries (vv.4-5). Whether Jacob actually gave these specific instructions before his death (ch.49 records no such statement) or whether the brothers have constructed a message in Jacob\'s name to soften their approach is a long-standing interpretive question. If the message is fabricated, it is a pious fiction — Jacob\'s real spirit of reconciliation translated into an authorizing message.</p>',

    "17": '<p>"Say to Joseph: I ask you to forgive your brothers the sins and the wrongs they committed in treating you so badly. Now please forgive the sins of the servants of the God of your father" — the brothers\' appeal invokes Jacob\'s authority and their shared religious identity ("servants of the God of your father"). "Joseph wept" — his weeping at the message is often interpreted as grief that his brothers still do not trust the reconciliation of ch.45, after years of living under his care and provision. The continued fear and the need for a posthumous appeal from Jacob indicates that genuine reconciliation is still incomplete despite the dramatic revelation scene.</p>',

    "18": '<p>"His brothers then came and threw themselves down before him. \'We are your slaves,\' they said" — the prostration and the self-identification as slaves (<em>avadekha anachnu</em>) fulfills Joseph\'s dream in its most literal form: not merely bowing but offering the extreme subordination of slavery. The irony is complete: in ch.37 they sold Joseph as a slave; in ch.50 they offer themselves as his slaves. The dream of the brothers\' sheaves bowing (37:7) has been fulfilled in multiple scenes throughout Genesis 42-50; this is its verbal and physical culmination. Joseph\'s response is to reject the slavery framework entirely.</p>',

    "19": '<p>"Don\'t be afraid. Am I in the place of God?" — Joseph\'s response rejects the role of divine judge and avenger. "In the place of God" (<em>hatachat Elohim ani</em>) — to take the place of God would be to assume divine prerogative over life, death, and retribution. The recognition that vengeance belongs to God rather than the human victim is embedded in later Torah (Deut 32:35: "It is mine to avenge; I will repay") and prophets; Joseph expresses it as intuitive theological reasoning without citing any law. His refusal of the avenger role is the practical outworking of the divine-sovereignty theology he expressed in ch.45:5-8.</p>',

    "20": '<p>"You intended to harm me, but God intended it for good to accomplish what is now being done — the saving of many lives" — the theological climax of the Joseph narrative: the verb "intended" (<em>hashav</em>, to devise, plan, reckon) governs both the brothers\' evil plan and God\'s good plan applied to the same event. <em>Atem hashavtem alai ra\'ah — Elohim hashavah letovah</em> (you devised against me evil — God devised it for good). The same verb. The same event. Two simultaneous intentional agents whose purposes were entirely opposite. This is a compressed theology of providence: God works concurrently through human decision — including human evil — toward purposes the actors cannot see. "The saving of many lives" (<em>lehachayot am-rav</em>) frames Joseph\'s entire Egyptian career as an act of large-scale preservation that transcends the family story.</p>',

    "21": '<p>"So then, don\'t be afraid. I will provide for you and your children. And he reassured them and spoke kindly to them" — the conclusion of the reconciliation scene repeats the "don\'t be afraid" formula used in v.19 (and in 43:23 and 45:5). "Spoke kindly to them" (<em>vayedabber al-libbam</em>, spoke to their hearts) is the same idiom used for the comfort of mourning (Ruth 2:13; Isa 40:2). The phrase marks the fullest available relational restoration: not just forgiveness and provision but a personal, sustained relationship maintained through speech that addresses the heart\'s fear rather than merely the surface situation.</p>',

    "22": '<p>"Joseph stayed in Egypt, along with all his father\'s family. He lived a hundred and ten years" — 110 years was the Egyptian ideal lifespan, documented in Middle Kingdom texts as the perfect length of a righteous official\'s life. The story of Ptahhotep (ca. 2400 BCE), the most famous Egyptian wisdom text, describes its protagonist\'s life of 110 years as divinely granted completion. Joseph dying at exactly 110 is not coincidence but a culturally embedded statement that his life was complete, blessed, and divinely favored — expressed in Egyptian cultural terms. This makes Joseph the only OT figure whose lifespan functions as an Egyptian honor rather than merely a Hebrew genealogical number.</p>',

    "23": '<p>"He saw the third generation of Ephraim\'s children. Also the children of Makir son of Manasseh were placed at birth on Joseph\'s knees" — seeing the third generation was considered exceptional longevity and blessing in the ANE; Job 42:16 similarly notes Job\'s four generations of descendants. "Placed at birth on Joseph\'s knees" is the ANE acknowledgment/adoption gesture: placing a newborn on the grandfather\'s knees formally incorporated the child into the family (cf. 30:3, where Bilhah\'s children are born "on Rachel\'s knees"; 48:12, where Joseph places his sons on Jacob\'s knees for blessing). Joseph formally acknowledges the great-grandchildren of Manasseh as members of the family in the same gesture his father used to acknowledge him and his brother.</p>',

    "24": '<p>"Then Joseph said to his brothers, \'I am about to die. But God will surely come to your aid and take you up out of this land to the land he promised on oath to Abraham, Isaac and Jacob\'" — Joseph\'s final speech is a confession of covenant faith expressed as a promise about the future: God will come to the family\'s aid (<em>paqod yifqod etkhem</em>, the emphatic infinitive absolute — God will surely visit/attend to you). The verb <em>paqad</em> (to visit/attend) is the term used in Exod 3:16 when God tells Moses to tell the elders "I have watched over you and have seen what has been done to you in Egypt" — the same verb fulfilling Joseph\'s prediction. Joseph\'s final words point forward beyond Genesis to the Exodus narrative.</p>',

    "25": '<p>"And Joseph made the Israelites swear an oath and said, \'God will surely come to your aid, and then you must carry my bones up from this place\'" — Joseph\'s bones-oath bridges Genesis and Exodus. Moses fulfills it in Exod 13:19 ("Moses took the bones of Joseph with him because Joseph had made the Israelites swear an oath"), and Joshua completes it in Josh 24:32 (Joseph\'s bones are buried at Shechem, in the field Jacob purchased from Hamor\'s sons — the same Shechem where Joseph was sent to find his brothers in 37:14). The bones-oath is a covenant act: Joseph\'s remains in Egypt are a pledge that the family will return to Canaan, and the obligation to carry them back is the family\'s commitment to the promised land even when generations may pass without the return.</p>',

    "26": '<p>"Joseph died at the age of a hundred and ten. And after they embalmed him, he was placed in a coffin in Egypt" — the final verse of Genesis ends with a coffin in Egypt. The word for coffin (<em>aron</em>) is the same word used for the ark of the covenant throughout Exodus-Deuteronomy — a lexical coincidence the narrator does not develop explicitly but that later interpreters have noted. The coffin in Egypt is the bridge object between Genesis and Exodus: it contains the remains of the man who brought Israel to Egypt, awaiting the man who will bring them out. Genesis ends not in the promised land but in exile, with a sealed coffin as the only physical monument to the covenant promises not yet fulfilled in that place.</p>',
  }
}

def main():
    existing = load_comm('mkt-context', 'genesis')
    merge_comm(existing, GENESIS)
    save_comm('mkt-context', 'genesis', existing)
    print('Genesis 49-50 mkt-context written.')

